import{_ as a,o as t,c as n,ag as s}from"./chunks/framework.CN92kLqn.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),i={name:"guide/architecture.md"};function r(o,e,d,p,c,l){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="technology-stack" tabindex="-1">Technology Stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Technology</th></tr></thead><tbody><tr><td>Runtime</td><td>Next.js 15 (App Router) + TypeScript</td></tr><tr><td>UI</td><td>Mantine v7 + Tailwind CSS</td></tr><tr><td>Database</td><td>SQLite (default) or MongoDB (multi-tenant)</td></tr><tr><td>Authentication</td><td>JWT via <code>jose</code> (Edge-compatible)</td></tr><tr><td>Logging</td><td>Winston (structured, JSON/pretty)</td></tr><tr><td>Cache</td><td>Memory or Redis (ioredis)</td></tr><tr><td>Email</td><td>Nodemailer + Handlebars templates</td></tr><tr><td>Build</td><td>Turbopack</td></tr><tr><td>Testing</td><td>Vitest</td></tr><tr><td>Deployment</td><td>Docker + Kubernetes (Helm)</td></tr></tbody></table><h2 id="request-flow" tabindex="-1">Request Flow <a class="header-anchor" href="#request-flow" aria-label="Permalink to &quot;Request Flow&quot;">​</a></h2><p>Every request goes through a well-defined pipeline:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client Request</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     ▼</span></span>
<span class="line"><span>┌─────────────┐</span></span>
<span class="line"><span>│  Middleware  │  ← JWT validation, feature checks, CORS</span></span>
<span class="line"><span>│  (Edge)     │     Injects: x-user-id, x-tenant-id, x-request-id</span></span>
<span class="line"><span>└──────┬──────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│ withRequestContext│  ← Establishes AsyncLocalStorage context</span></span>
<span class="line"><span>│  (Route wrapper) │     Checks isShuttingDown → 503</span></span>
<span class="line"><span>└──────┬──────────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Route Handler  │  ← requireApiToken (client routes)</span></span>
<span class="line"><span>│                 │     Validation, quota checks</span></span>
<span class="line"><span>└──────┬──────────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Domain Service │  ← Business logic</span></span>
<span class="line"><span>│  (inference,    │     Uses: runtimePool, withResilience, cache</span></span>
<span class="line"><span>│   vector, etc.) │</span></span>
<span class="line"><span>└──────┬──────────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Provider       │  ← External API call (LLM, vector DB, etc.)</span></span>
<span class="line"><span>│  Runtime        │     Wrapped in withResilience (retry + circuit breaker)</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h2 id="multi-tenant-data-model" tabindex="-1">Multi-Tenant Data Model <a class="header-anchor" href="#multi-tenant-data-model" aria-label="Permalink to &quot;Multi-Tenant Data Model&quot;">​</a></h2><p>The gateway supports two database backends. <strong>SQLite</strong> is the default for zero-dependency setups; <strong>MongoDB</strong> is available for production deployments requiring higher concurrency.</p><h3 id="sqlite-default" tabindex="-1">SQLite (default) <a class="header-anchor" href="#sqlite-default" aria-label="Permalink to &quot;SQLite (default)&quot;">​</a></h3><p>Each tenant gets a separate <code>.sqlite</code> file — full data isolation with no external services:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data/</span></span>
<span class="line"><span>├── console_main.sqlite       # Shared database (tenant registry)</span></span>
<span class="line"><span>├── tenant_acme.sqlite        # Tenant &quot;acme&quot;</span></span>
<span class="line"><span>├── tenant_globex.sqlite      # Tenant &quot;globex&quot;</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><h3 id="mongodb" tabindex="-1">MongoDB <a class="header-anchor" href="#mongodb" aria-label="Permalink to &quot;MongoDB&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MongoDB Server</span></span>
<span class="line"><span>├── console_main             # Shared database</span></span>
<span class="line"><span>│   └── tenants              # Tenant metadata, license, slug</span></span>
<span class="line"><span>├── tenant_{slug}            # Per-company database</span></span>
<span class="line"><span>│   ├── users                # User accounts</span></span>
<span class="line"><span>│   ├── api_tokens           # API tokens</span></span>
<span class="line"><span>│   ├── projects             # Projects</span></span>
<span class="line"><span>│   ├── models               # Model configurations</span></span>
<span class="line"><span>│   ├── provider_configs     # Provider credentials (encrypted)</span></span>
<span class="line"><span>│   ├── vector_indexes       # Vector index metadata</span></span>
<span class="line"><span>│   ├── model_usage_logs     # Inference usage logs</span></span>
<span class="line"><span>│   ├── agent_tracing_*      # Tracing sessions &amp; events</span></span>
<span class="line"><span>│   ├── guardrails           # Guardrail policies</span></span>
<span class="line"><span>│   ├── prompts              # Prompt templates</span></span>
<span class="line"><span>│   ├── rag_modules          # RAG configurations</span></span>
<span class="line"><span>│   ├── memory_stores        # Memory store configs</span></span>
<span class="line"><span>│   └── ...</span></span>
<span class="line"><span>└── tenant_{another_slug}    # Another company (complete isolation)</span></span></code></pre></div><p>Switch between providers with <code>DB_PROVIDER=sqlite</code> (default) or <code>DB_PROVIDER=mongodb</code>.</p><h2 id="core-module-stack" tabindex="-1">Core Module Stack <a class="header-anchor" href="#core-module-stack" aria-label="Permalink to &quot;Core Module Stack&quot;">​</a></h2><p>The infrastructure layer (<code>src/lib/core/</code>) provides cross-cutting concerns that are used by all services:</p><table tabindex="0"><thead><tr><th>Module</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="/cgate/guide/core-config.html">Config</a></td><td>Centralized typed configuration with ENV abstraction</td></tr><tr><td><a href="/cgate/guide/core-logger.html">Logger</a></td><td>Structured logging with automatic request context</td></tr><tr><td><a href="/cgate/guide/core-request-context.html">Request Context</a></td><td>Per-request AsyncLocalStorage propagation</td></tr><tr><td><a href="/cgate/guide/core-cache.html">Cache</a></td><td>Provider-based caching (none / memory / Redis)</td></tr><tr><td><a href="/cgate/guide/core-resilience.html">Resilience</a></td><td>Retry with exponential back-off + circuit breaker</td></tr><tr><td><a href="/cgate/guide/core-runtime-pool.html">Runtime Pool</a></td><td>LRU cache for provider SDK client instances</td></tr><tr><td><a href="/cgate/guide/core-async-tasks.html">Async Tasks</a></td><td>Fire-and-forget background operations</td></tr><tr><td><a href="/cgate/guide/core-health.html">Health Checks</a></td><td>Subsystem health registry for readiness probes</td></tr><tr><td><a href="/cgate/guide/core-lifecycle.html">Lifecycle</a></td><td>Graceful shutdown with ordered handler teardown</td></tr><tr><td><a href="/cgate/guide/core-cors.html">CORS</a></td><td>Configurable CORS for client API endpoints</td></tr></tbody></table><h2 id="bootstrap-sequence" tabindex="-1">Bootstrap Sequence <a class="header-anchor" href="#bootstrap-sequence" aria-label="Permalink to &quot;Bootstrap Sequence&quot;">​</a></h2><p>The application bootstrap is managed by <code>src/instrumentation.ts</code> (Next.js instrumentation hook):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Validate config (getConfig + validateConfig)</span></span>
<span class="line"><span>2. Initialize lifecycle (signal handlers: SIGTERM, SIGINT)</span></span>
<span class="line"><span>3. Initialize cache provider (memory / Redis / none)</span></span>
<span class="line"><span>4. Register health check for cache</span></span>
<span class="line"><span>5. Register shutdown handlers (async-tasks → cache → runtime-pool)</span></span>
<span class="line"><span>6. Start background schedulers (inference monitoring, alerts)</span></span>
<span class="line"><span>7. Log startup summary</span></span></code></pre></div><h2 id="service-layer" tabindex="-1">Service Layer <a class="header-anchor" href="#service-layer" aria-label="Permalink to &quot;Service Layer&quot;">​</a></h2><p>Business logic is in <code>src/lib/services/</code>:</p><table tabindex="0"><thead><tr><th>Service</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>models/inferenceService</code></td><td>Chat completions &amp; embeddings (OpenAI-compatible)</td></tr><tr><td><code>models/runtimeService</code></td><td>Provider runtime creation with pool caching</td></tr><tr><td><code>models/modelService</code></td><td>Model CRUD with metadata caching</td></tr><tr><td><code>vector/vectorService</code></td><td>Vector index CRUD, upsert, query</td></tr><tr><td><code>files/fileService</code></td><td>File upload/download/delete via provider runtime</td></tr><tr><td><code>guardrail/</code></td><td>Input/output evaluation with regex/keyword/LLM</td></tr><tr><td><code>agentTracing/</code></td><td>Tracing session &amp; event persistence</td></tr><tr><td><code>providers/providerService</code></td><td>Provider config CRUD, credential encryption</td></tr><tr><td><code>rag/</code></td><td>RAG module management, document ingestion, queries</td></tr><tr><td><code>memory/</code></td><td>Memory store CRUD, semantic search</td></tr><tr><td><code>prompts/</code></td><td>Prompt template management, versioning</td></tr><tr><td><code>apiTokenAuth</code></td><td>API token validation with caching</td></tr></tbody></table>`,23)])])}const g=a(i,[["render",r]]);export{u as __pageData,g as default};
